//! ISLS v3.1 — Template-Free LLM Generation Engine.
//!
//! Replaces Tera-template emission with an LLM-driven, compile-verified
//! pipeline.  Every file is generated by an LLM whose prompt includes ALL
//! types produced so far (the *growing TypeContext*), eliminating hallucinated
//! field names.
//!
//! # Pipeline
//! ```text
//! AppSpec  →  LlmForge::generate()
//!   Layer 0: static files (Cargo.toml, docker-compose.yml, Dockerfile, …)
//!   Layer 1: Foundation (errors.rs, config.rs, pagination.rs)
//!   Layer 2: Auth (models/user.rs, auth.rs)
//!   Layer 3: Models ({entity}.rs)
//!   Layer 4: Database (migrations, queries, pool)
//!   Layer 5: Services ({entity}.rs)
//!   Layer 6: API ({entity}.rs, auth_routes.rs)
//!   Layer 7: main.rs
//!   Layer 8: Frontend (index.html, CSS, JS)
//!   Layer 9: Tests (api_tests.rs)
//! ```
//!
//! # Example
//! ```rust,ignore
//! use isls_forge_llm::{LlmForge, ForgePlan, AppSpec};
//! use isls_forge_llm::oracle::MockOracle;
//!
//! let oracle = Box::new(MockOracle);
//! let plan = ForgePlan::warehouse_default("warehouse-app");
//! let mut forge = LlmForge::new(oracle, plan, "/tmp/out".into(), true);
//! let files = forge.generate().unwrap();
//! ```

